const body = $input.first().json.body || $input.first().json;
const emailId = body.email_id;
const subject = body.subject || '';
const threadLength = body.thread_length || 0;
const sender = body.sender || '';
const ownerAgent = body.owner_agent || '';

if (!emailId) {
  throw new Error('Missing required field: email_id');
}

return [{
  json: {
    email_id: emailId,
    subject: subject,
    thread_length: threadLength,
    sender: sender,
    owner_agent: ownerAgent
  }
}];

const threadData = $input.first().json;
const messages = threadData.messages || threadData.thread || threadData.data || [];
const emailMeta = $('Validate Webhook Payload').first().json;

// Build a text representation of the thread for Ollama
// IMPORTANT: This goes to Ollama (localhost) ONLY — never to any external API
let threadText = `Subject: ${emailMeta.subject}\n`;
threadText += `Thread length: ${emailMeta.thread_length} messages\n`;
threadText += `From: ${emailMeta.sender}\n\n`;

if (Array.isArray(messages)) {
  for (const msg of messages) {
    const from = msg.from || msg.sender || 'Unknown';
    const date = msg.date || msg.sent_at || '';
    const body = msg.body || msg.content || msg.text || '';
    threadText += `--- ${from} (${date}) ---\n${body}\n\n`;
  }
} else if (typeof threadData === 'string') {
  threadText += threadData;
} else {
  threadText += JSON.stringify(threadData, null, 2).substring(0, 4000);
}

return [{
  json: {
    thread_text: threadText,
    email_id: emailMeta.email_id,
    owner_agent: emailMeta.owner_agent,
    subject: emailMeta.subject
  }
}];

const ollamaResponse = $input.first().json.response || '';
const meta = $('Prepare Thread for Ollama').first().json;

// Extract suggested action from the summary
const actionPatterns = [
  /action[s]?\s*(?:needed|required|recommended)?\s*[:.]\s*(.+?)(?:\.|$)/i,
  /(?:should|need to|must|recommend)\s+(.+?)(?:\.|$)/i
];

let suggestedAction = '';
for (const pattern of actionPatterns) {
  const match = ollamaResponse.match(pattern);
  if (match) {
    suggestedAction = match[1].trim();
    break;
  }
}

if (!suggestedAction) {
  suggestedAction = 'Review summary and determine next steps';
}

return [{
  json: {
    email_id: meta.email_id,
    subject: meta.subject,
    summary: ollamaResponse,
    suggested_action: suggestedAction,
    owner_agent: meta.owner_agent,
    processed_at: new Date().toISOString()
  }
}];
